+// Torch flame animation frames (simple flicker offsets)
+const TORCH_FLAME_OFFSETS = [
+  { dx: 0, dy: 0 },
+  { dx: 1, dy: -1 },
+  { dx: -1, dy: 1 },
+  { dx: 0, dy: 1 },
+  { dx: 1, dy: 0 },
+];
+
+function drawTorch(ctx: CanvasRenderingContext2D, x: number, y: number, frame: number) {
+  // Draw torch base (wood handle)
+  ctx.fillStyle = '#4a2810';
+  ctx.fillRect(x + 2, y + 4, 4, 14);
+  ctx.fillStyle = '#5c3418';
+  ctx.fillRect(x + 3, y + 5, 2, 12);
+
+  // Draw metal holder
+  ctx.fillStyle = '#4a4a58';
+  ctx.fillRect(x + 1, y + 10, 6, 4);
+  ctx.fillRect(x + 5, y + 8, 3, 8);
+
+  // Animate flame with flicker offsets
+  const flicker = TORCH_FLAME_OFFSETS[frame % TORCH_FLAME_OFFSETS.length];
+  const fx = x + 4 + flicker.dx;
+  const fy = y - 4 + flicker.dy;
+
+  // Flame layers with radial gradient glow
+  const flameRadius = 8;
+  const flameGradient = ctx.createRadialGradient(fx, fy, 0, fx, fy, flameRadius);
+  flameGradient.addColorStop(0, 'rgba(255, 180, 60, 0.8)');
+  flameGradient.addColorStop(0.5, 'rgba(255, 140, 20, 0.4)');
+  flameGradient.addColorStop(1, 'rgba(255, 80, 0, 0)');
+  ctx.fillStyle = flameGradient;
+  ctx.beginPath();
+  ctx.ellipse(fx, fy, flameRadius, flameRadius * 1.5, 0, 0, Math.PI * 2);
+  ctx.fill();
+
+  // Inner flame core
+  ctx.fillStyle = 'rgba(255, 255, 180, 0.9)';
+  ctx.beginPath();
+  ctx.ellipse(fx, fy, flameRadius * 0.5, flameRadius * 0.75, 0, 0, Math.PI * 2);
+  ctx.fill();
+}
+
+function drawRoomLighting(ctx: CanvasRenderingContext2D, type: CharacterType, x: number, y: number, w: number, h: number) {
+  // Base ambient radial lights at corners
+  const cornerRadius = Math.max(w, h) * 0.4;
+  for (const [cx, cy] of [[x, y], [x + w, y], [x, y + h], [x + w, y + h]] as [number, number][]) {
+    const grad = ctx.createRadialGradient(cx, cy, 0, cx, cy, cornerRadius);
+    grad.addColorStop(0, 'rgba(0,0,0,0.2)');
+    grad.addColorStop(1, 'rgba(0,0,0,0)');
+    ctx.fillStyle = grad;
+    ctx.fillRect(cx - cornerRadius, cy - cornerRadius, cornerRadius * 2, cornerRadius * 2);
+  }
+
+  // Add torch light sources per room type with radial glow
+  const torchPositions: [number, number][] = [];
+  switch (type) {
+    case 'king':
+      torchPositions.push([x + w * 0.02, y + h * 0.15], [x + w * 0.92, y + h * 0.15]);
+      break;
+    case 'nobility':
+      torchPositions.push([x + w * 0.02, y + h * 0.12]);
+      torchPositions.push([x + w * 0.85, y + h * 0.15]);
+      break;
+    case 'knight':
+      torchPositions.push([x + w * 0.5, y + h * 0.06]);
+      break;
+    case 'squire':
+      torchPositions.push([x + w * 0.88, y + h * 0.1]);
+      break;
+    case 'healer':
+      // Healer room has ambient glow, add torches if any
+      break;
+    case 'sentinel':
+      torchPositions.push([x + w * 0.02, y + h * 0.28], [x + w * 0.9, y + h * 0.28]);
+      break;
+    case 'scribe':
+      // No torches by default
+      break;
+    case 'judge':
+      torchPositions.push([x + w * 0.08, y + h * 0.15], [x + w * 0.85, y + h * 0.15]);
+      break;
+    case 'blacksmith':
+      torchPositions.push([x + w * 0.38, y + h * 0.06]);
+      break;
+  }
+
+  // Draw radial glow for each torch
+  for (const [tx, ty] of torchPositions) {
+    const radius = Math.min(w, h) * 0.25;
+    const grad = ctx.createRadialGradient(tx, ty, 0, tx, ty, radius);
+    grad.addColorStop(0, 'rgba(255, 180, 60, 0.3)');
+    grad.addColorStop(0.5, 'rgba(255, 140, 20, 0.15)');
+    grad.addColorStop(1, 'rgba(255, 80, 0, 0)');
+    ctx.fillStyle = grad;
+    ctx.fillRect(tx - radius, ty - radius, radius * 2, radius * 2);
+  }
+
+  // Special ambient glow for healer and king rooms
+  if (type === 'healer' || type === 'king') {
+    const glowRadius = w * 0.45;
+    const glowX = x + w / 2;
+    const glowY = y + h * 0.5;
+    const grad = ctx.createRadialGradient(glowX, glowY, 0, glowX, glowY, glowRadius);
+    grad.addColorStop(0, 'rgba(255, 200, 100, 0.04)');
+    grad.addColorStop(1, 'rgba(255, 200, 100, 0)');
+    ctx.fillStyle = grad;
+    ctx.fillRect(x, y, w, h);
+  }
+}
+
